defmodule SessionPlug do
  import Plug.Conn

  @session_cookie_name "app_session"
  @cookie_opts [
    max_age: 3600,
    http_only: true,
    secure: false,
    same_site: "Lax"
  ]

  def init(opts), do: opts

  def call(conn, _opts) do
    session_cookie = conn.req_cookies[@session_cookie_name]
    
    case SessionManager.deserialize_session(session_cookie) do
      {:ok, session} ->
        conn
        |> assign(:current_session, session)
        |> assign(:current_user_id, session.user_id)
      {:error, _reason} ->
        conn
        |> assign(:current_session, nil)
        |> assign(:current_user_id, nil)
    end
  end

  def put_session(conn, user_id, data \\ %{}) do
    session_data = SessionManager.create_session(user_id, data)
    put_resp_cookie(conn, @session_cookie_name, session_data, @cookie_opts)
  end

  def update_session(conn, updates) do
    case conn.req_cookies[@session_cookie_name] do
      nil ->
        conn
      session_cookie ->
        case SessionManager.update_session(session_cookie, updates) do
          {:ok, new_session_data} ->
            put_resp_cookie(conn, @session_cookie_name, new_session_data, @cookie_opts)
          {:error, _} ->
            conn
        end
    end
  end

  def refresh_session(conn) do
    case conn.req_cookies[@session_cookie_name] do
      nil ->
        conn
      session_cookie ->
        case SessionManager.refresh_session(session_cookie) do
          {:ok, new_session_data} ->
            put_resp_cookie(conn, @session_cookie_name, new_session_data, @cookie_opts)
          {:error, _} ->
            conn
        end
    end
  end

  def delete_session(conn) do
    delete_resp_cookie(conn, @session_cookie_name, @cookie_opts)
  end

  def get_session_data(conn) do
    case conn.assigns[:current_session] do
      nil -> %{}
      session -> session.data
    end
  end

  def get_current_user_id(conn) do
    conn.assigns[:current_user_id]
  end
end

